  ('retired-8b44517b-moex-00076', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政法法源，下列敘述何者正確？', '["各種法源效力平等，無位階之分", "行政法法源不僅只有成文法法源，一般法律原則亦為法源", "行政規則之訂定屬於行政行為，不得作為行政法之法源", "僅有通過立法行為，方能產生法源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00077', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '依司法院解釋意旨，關於層級化法律保留，下列敘述何者錯誤？', '["何種事項應以法律直接規範或得委由法規命令予以規定，與所涉權利義務有關", "若屬執行法律之細節性、技術性次要事項，則無須法律授權，得由行政機關依職權訂定行政規 則規範", "關於給付行政，法律規範密度較為寬鬆，倘涉及公共利益重大事項，仍有法律保留原則之適用", "涉及人民自由權利之限制者，如財產權，強調國會保留，即不得授權命令為補充性規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00078', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["社會秩序維護法第29條規定，違反本法行為之情節可憫恕者，得減輕或免除其處罰，屬於決 定裁量之範圍", "行政機關所選定之法律效果，逾越法律所授權之裁量範圍，則構成裁量逾越之瑕疵", "行政機關若消極地未斟酌具體個案情節，就作出決定，即構成裁量怠惰之瑕疵", "行政機關為裁量時，不受平等原則拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00079', 'retired-8b44517b', 'retired-8b44517b-moex-114-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於地方自治團體權限之敘述，下列何者錯誤？', '["地方自治團體具有財政自主權，中央不得以法律規定地方分擔基於國家整體施政所需之經費", "地方自治團體有就自治事項制定規章並執行之權限", "地方自治團體對其是否設置特定機關或事業機構，享有自主組織權", "法律規定得設置之職位，地方自治團體既有自主決定設置與否之權限，仍應有組織自治條例之 依據始得進用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:05+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "133", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL)
